package com.schoolbus.controller;
import com.schoolbus.dto.request.*;import com.schoolbus.dto.response.*;import com.schoolbus.service.AdminCrudService;import jakarta.validation.Valid;import org.springframework.data.domain.*;import org.springframework.http.*;import org.springframework.web.bind.annotation.*;
@RestController @RequestMapping("/api/v1/admin/parents") public class AdminParentController{private final AdminCrudService s;public AdminParentController(AdminCrudService s){this.s=s;}@GetMapping public ApiResponse<PageResponse<ParentResponse>> list(@RequestParam(required=false)String search,@RequestParam(defaultValue="0")int page,@RequestParam(defaultValue="20")int size){return ApiResponse.success(PageResponse.from(s.parents(search,PageRequest.of(page,size))));}@GetMapping("/{id}")public ApiResponse<ParentResponse> get(@PathVariable Long id){return ApiResponse.success(s.parent(id));}@PostMapping public ResponseEntity<ApiResponse<ParentResponse>> create(@Valid @RequestBody ParentRequest r){return ResponseEntity.status(HttpStatus.CREATED).body(ApiResponse.success("Parent created",s.createParent(r)));}@PutMapping("/{id}")public ApiResponse<ParentResponse> update(@PathVariable Long id,@Valid @RequestBody ParentRequest r){return ApiResponse.success(s.updateParent(id,r));}@PatchMapping("/{id}/deactivate")public ApiResponse<Void> deactivate(@PathVariable Long id){s.deactivateParent(id);return ApiResponse.success("Parent deactivated",null);}}
